import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface User {
  id: string;
  name: string;
  email: string;
  avatar: string;
  karma: number;
  contributions: number;
  role: 'user' | 'TA' | 'admin';
  joinedAt: string;
}

export interface Question {
  id: string;
  title: string;
  content: string;
  course: string;
  tags: string[];
  userId: string;
  userName: string;
  userAvatar: string;
  anonymous: boolean;
  votes: number;
  answerCount: number;
  resolved: boolean;
  urgent: boolean;
  createdAt: string;
}

export interface Answer {
  id: string;
  questionId: string;
  content: string;
  userId: string;
  userName: string;
  userAvatar: string;
  anonymous: boolean;
  votes: number;
  isBest: boolean;
  createdAt: string;
}

export interface Resource {
  id: string;
  title: string;
  description: string;
  course: string;
  tags: string[];
  link: string;
  userId: string;
  userName: string;
  votes: number;
  downloads: number;
  createdAt: string;
}

export interface Vote {
  userId: string;
  targetId: string;
  value: 1 | -1;
}

export enum KarmaReward {
  ASK_QUESTION = 5,
  ANSWER_QUESTION = 10,
  SHARE_RESOURCE = 15,
  BEST_ANSWER = 20,
  RECEIVE_UPVOTE = 1
}

import { GoogleGenAI } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const getAISummary = async (question: string) => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `You are a helpful study assistant for university students. 
      Briefly summarize the key points or provide a helpful hint for this question: "${question}". 
      Keep it academic and concise.`,
    });
    return response.text;
  } catch (error) {
    console.error("AI Assistant Error:", error);
    return "Sorry, I couldn't generate a summary right now. Please try again later.";
  }
};

import React, { createContext, useContext, useState, useEffect, useCallback } from 'react';
import { User, Question, Answer, Resource, KarmaReward } from '../types';
import { MOCK_USERS, MOCK_QUESTIONS, MOCK_RESOURCES } from '../constants';

interface AppContextType {
  user: User | null;
  questions: Question[];
  resources: Resource[];
  answers: Answer[];
  login: (email: string) => void;
  logout: () => void;
  addQuestion: (q: Partial<Question>) => void;
  addResource: (r: Partial<Resource>) => void;
  addAnswer: (a: Partial<Answer>) => void;
  vote: (targetId: string, type: 'question' | 'resource' | 'answer', value: 1 | -1) => void;
  updateKarma: (amount: number) => void;
}

const AppContext = createContext<AppContextType | undefined>(undefined);

export const AppProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [user, setUser] = useState<User | null>(null);
  const [questions, setQuestions] = useState<Question[]>(MOCK_QUESTIONS);
  const [resources, setResources] = useState<Resource[]>(MOCK_RESOURCES);
  const [answers, setAnswers] = useState<Answer[]>([]);

  // Simulation of persistent auth
  useEffect(() => {
    const savedUser = localStorage.getItem('studyhub_user');
    if (savedUser) {
      setUser(JSON.parse(savedUser));
    }
  }, []);

  const login = (email: string) => {
    // Basic campus email validation
    if (!email.endsWith('.edu')) {
      alert("Only campus emails (.edu) are allowed.");
      return;
    }
    const newUser: User = {
      ...MOCK_USERS[0],
      email,
      id: Math.random().toString(36).substr(2, 9)
    };
    setUser(newUser);
    localStorage.setItem('studyhub_user', JSON.stringify(newUser));
  };

  const logout = () => {
    setUser(null);
    localStorage.removeItem('studyhub_user');
  };

  const updateKarma = (amount: number) => {
    if (!user) return;
    const updatedUser = { ...user, karma: user.karma + amount };
    setUser(updatedUser);
    localStorage.setItem('studyhub_user', JSON.stringify(updatedUser));
  };

  const addQuestion = (q: Partial<Question>) => {
    if (!user) return;
    const newQ: Question = {
      id: Math.random().toString(36).substr(2, 9),
      title: q.title || '',
      content: q.content || '',
      course: q.course || '',
      tags: q.tags || [],
      userId: user.id,
      userName: q.anonymous ? 'Anonymous' : user.name,
      userAvatar: q.anonymous ? 'https://picsum.photos/seed/anon/200' : user.avatar,
      anonymous: !!q.anonymous,
      votes: 0,
      answerCount: 0,
      resolved: false,
      urgent: !!q.urgent,
      createdAt: new Date().toISOString(),
    };
    setQuestions([newQ, ...questions]);
    updateKarma(KarmaReward.ASK_QUESTION);
  };

  const addResource = (r: Partial<Resource>) => {
    if (!user) return;
    const newR: Resource = {
      id: Math.random().toString(36).substr(2, 9),
      title: r.title || '',
      description: r.description || '',
      course: r.course || '',
      tags: r.tags || [],
      link: r.link || '',
      userId: user.id,
      userName: user.name,
      votes: 0,
      downloads: 0,
      createdAt: new Date().toISOString(),
    };
    setResources([newR, ...resources]);
    updateKarma(KarmaReward.SHARE_RESOURCE);
  };

  const addAnswer = (a: Partial<Answer>) => {
    if (!user) return;
    const newA: Answer = {
      id: Math.random().toString(36).substr(2, 9),
      questionId: a.questionId || '',
      content: a.content || '',
      userId: user.id,
      userName: a.anonymous ? 'Anonymous' : user.name,
      userAvatar: a.anonymous ? 'https://picsum.photos/seed/anon/200' : user.avatar,
      anonymous: !!a.anonymous,
      votes: 0,
      isBest: false,
      createdAt: new Date().toISOString(),
    };
    setAnswers([newA, ...answers]);
    setQuestions(questions.map(q => q.id === a.questionId ? { ...q, answerCount: q.answerCount + 1 } : q));
    updateKarma(KarmaReward.ANSWER_QUESTION);
  };

  const vote = (targetId: string, type: 'question' | 'resource' | 'answer', value: 1 | -1) => {
    if (type === 'question') {
      setQuestions(questions.map(q => q.id === targetId ? { ...q, votes: q.votes + value } : q));
    } else if (type === 'resource') {
      setResources(resources.map(r => r.id === targetId ? { ...r, votes: r.votes + value } : r));
    } else if (type === 'answer') {
      setAnswers(answers.map(ans => ans.id === targetId ? { ...ans, votes: ans.votes + value } : ans));
    }
    updateKarma(KarmaReward.RECEIVE_UPVOTE);
  };

  return (
    <AppContext.Provider value={{ user, questions, resources, answers, login, logout, addQuestion, addResource, addAnswer, vote, updateKarma }}>
      {children}
    </AppContext.Provider>
  );
};

export const useApp = () => {
  const context = useContext(AppContext);
  if (!context) throw new Error("useApp must be used within an AppProvider");
  return context;
};

