import React, { useState } from 'react';
import { AppProvider, useApp } from './context/AppContext';
import Layout from './components/Layout';
import LandingPage from './pages/LandingPage';
import Dashboard from './pages/Dashboard';
import QuestionDetailPage from './pages/QuestionDetailPage';
import LeaderboardPage from './pages/LeaderboardPage';
import ProfilePage from './pages/ProfilePage';
import AskModal from './components/AskModal';
import ShareModal from './components/ShareModal';

const AppContent: React.FC = () => {
  const { user } = useApp();
  const [activeTab, setActiveTab] = useState('dashboard');
  const [selectedQuestionId, setSelectedQuestionId] = useState<string | null>(null);
  const [showAskModal, setShowAskModal] = useState(false);
  const [showShareModal, setShowShareModal] = useState(false);
  const [searchQuery, setSearchQuery] = useState('');

  if (!user) {
    return <LandingPage />;
  }

  // Routing Simulation
  const handleTabChange = (tab: string) => {
    setActiveTab(tab);
    setSelectedQuestionId(null);
    setSearchQuery('');
  };

  const handleSearch = (term: string) => {
    setSearchQuery(term);
    setActiveTab('dashboard');
  };

  const renderContent = () => {
    if (selectedQuestionId) {
      return <QuestionDetailPage questionId={selectedQuestionId} onBack={() => setSelectedQuestionId(null)} />;
    }

    switch (activeTab) {
      case 'dashboard':
        return <Dashboard onSelectQuestion={setSelectedQuestionId} searchQuery={searchQuery} />;
      case 'leaderboard':
        return <LeaderboardPage />;
      case 'profile':
        return <ProfilePage />;
      default:
        return <Dashboard onSelectQuestion={setSelectedQuestionId} searchQuery={searchQuery} />;
    }
  };

  return (
    <Layout activeTab={activeTab} onTabChange={handleTabChange} onSearch={handleSearch}>
      {renderContent()}

      {/* FABs */}
      <div className="fixed bottom-8 right-8 flex flex-col gap-3 z-40">
        <button 
          onClick={() => setShowShareModal(true)}
          className="bg-indigo-600 hover:bg-indigo-700 text-white w-14 h-14 rounded-full shadow-lg flex items-center justify-center transition-transform hover:scale-110 group relative"
        >
          <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-8l-4-4m0 0l-4-4m4 4v12" /></svg>
          <span className="absolute right-full mr-3 bg-indigo-900 text-white text-xs px-2 py-1 rounded hidden group-hover:block whitespace-nowrap">Share Resource</span>
        </button>
        <button 
          onClick={() => setShowAskModal(true)}
          className="bg-blue-600 hover:bg-blue-700 text-white w-14 h-14 rounded-full shadow-lg flex items-center justify-center transition-transform hover:scale-110 group relative"
        >
          <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4v16m8-8H4" /></svg>
          <span className="absolute right-full mr-3 bg-blue-900 text-white text-xs px-2 py-1 rounded hidden group-hover:block whitespace-nowrap">Ask Question</span>
        </button>
      </div>

      <AskModal isOpen={showAskModal} onClose={() => setShowAskModal(false)} />
      <ShareModal isOpen={showShareModal} onClose={() => setShowShareModal(false)} />
    </Layout>
  );
};

const App: React.FC = () => {
  return (
    <AppProvider>
      <AppContent />
    </AppProvider>
  );
};

export default App;

import React, { useState, useMemo } from 'react';
import { useApp } from '../context/AppContext';
import { QuestionCard, ResourceCard } from '../components/Cards';
import { POPULAR_COURSES } from '../constants';
import { BarChart, Bar, XAxis, YAxis, Tooltip, ResponsiveContainer, Cell } from 'recharts';

const Dashboard: React.FC<{ onSelectQuestion: (id: string) => void; searchQuery: string }> = ({ onSelectQuestion, searchQuery }) => {
  const { questions, resources, user } = useApp();
  const [activeTab, setActiveTab] = useState<'questions' | 'resources' | 'my'>('questions');
  const [selectedCourse, setSelectedCourse] = useState<string | null>(null);

  const statsData = [
    { name: 'Questions', val: 124, color: '#3B82F6' },
    { name: 'Answers', val: 89, color: '#10B981' },
    { name: 'Materials', val: 45, color: '#8B5CF6' }
  ];

  const filteredQuestions = useMemo(() => {
    let qs = questions;
    if (searchQuery) {
      qs = qs.filter(q => q.title.toLowerCase().includes(searchQuery.toLowerCase()) || q.content.toLowerCase().includes(searchQuery.toLowerCase()));
    }
    if (selectedCourse) {
      qs = qs.filter(q => q.course === selectedCourse);
    }
    return qs;
  }, [questions, searchQuery, selectedCourse]);

  const filteredResources = useMemo(() => {
    let rs = resources;
    if (searchQuery) {
      rs = rs.filter(r => r.title.toLowerCase().includes(searchQuery.toLowerCase()) || r.description.toLowerCase().includes(searchQuery.toLowerCase()));
    }
    if (selectedCourse) {
      rs = rs.filter(r => r.course === selectedCourse);
    }
    return rs;
  }, [resources, searchQuery, selectedCourse]);

  const myContributions = useMemo(() => {
    return [
      ...questions.filter(q => q.userId === user?.id).map(q => ({ ...q, type: 'question' as const })),
      ...resources.filter(r => r.userId === user?.id).map(r => ({ ...r, type: 'resource' as const }))
    ].sort((a, b) => new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime());
  }, [questions, resources, user]);

  return (
    <div className="grid lg:grid-cols-4 gap-8">
      {/* Sidebar */}
      <aside className="space-y-8 order-2 lg:order-1">
        <div className="bg-white rounded-2xl border border-slate-200 p-6 shadow-sm">
          <h3 className="text-sm font-bold text-slate-900 uppercase tracking-wider mb-4">Popular Courses</h3>
          <div className="flex flex-col gap-2">
            <button 
              onClick={() => setSelectedCourse(null)}
              className={`text-left text-sm py-2 px-3 rounded-lg transition-colors ${!selectedCourse ? 'bg-blue-50 text-blue-600 font-medium' : 'hover:bg-slate-50 text-slate-600'}`}
            >
              All Courses
            </button>
            {POPULAR_COURSES.map(course => (
              <button 
                key={course}
                onClick={() => setSelectedCourse(course)}
                className={`text-left text-sm py-2 px-3 rounded-lg transition-colors ${selectedCourse === course ? 'bg-blue-50 text-blue-600 font-medium' : 'hover:bg-slate-50 text-slate-600'}`}
              >
                {course}
              </button>
            ))}
          </div>
        </div>

        <div className="bg-white rounded-2xl border border-slate-200 p-6 shadow-sm">
          <h3 className="text-sm font-bold text-slate-900 uppercase tracking-wider mb-4">Today's Activity</h3>
          <div className="h-40 w-full">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={statsData}>
                <XAxis dataKey="name" fontSize={10} axisLine={false} tickLine={false} />
                <Tooltip cursor={{fill: 'transparent'}} contentStyle={{borderRadius: '12px', border: 'none', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)'}} />
                <Bar dataKey="val" radius={[4, 4, 4, 4]}>
                  {statsData.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill={entry.color} />
                  ))}
                </Bar>
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>
      </aside>

      {/* Main Area */}
      <div className="lg:col-span-3 space-y-6 order-1 lg:order-2">
        <div className="flex items-center gap-4 border-b border-slate-200">
          <button 
            onClick={() => setActiveTab('questions')}
            className={`pb-3 text-sm font-bold px-4 transition-all relative ${activeTab === 'questions' ? 'text-blue-600' : 'text-slate-500 hover:text-slate-800'}`}
          >
            Questions
            {activeTab === 'questions' && <div className="absolute bottom-0 left-0 right-0 h-1 bg-blue-600 rounded-t-full"></div>}
          </button>
          <button 
            onClick={() => setActiveTab('resources')}
            className={`pb-3 text-sm font-bold px-4 transition-all relative ${activeTab === 'resources' ? 'text-blue-600' : 'text-slate-500 hover:text-slate-800'}`}
          >
            Resources
            {activeTab === 'resources' && <div className="absolute bottom-0 left-0 right-0 h-1 bg-blue-600 rounded-t-full"></div>}
          </button>
          <button 
            onClick={() => setActiveTab('my')}
            className={`pb-3 text-sm font-bold px-4 transition-all relative ${activeTab === 'my' ? 'text-blue-600' : 'text-slate-500 hover:text-slate-800'}`}
          >
            My Contributions
            {activeTab === 'my' && <div className="absolute bottom-0 left-0 right-0 h-1 bg-blue-600 rounded-t-full"></div>}
          </button>
        </div>

        <div className="grid gap-4">
          {activeTab === 'questions' && (
            filteredQuestions.length > 0 ? (
              filteredQuestions.map(q => <QuestionCard key={q.id} question={q} onClick={() => onSelectQuestion(q.id)} />)
            ) : (
              <EmptyState title="No questions found" subtitle="Be the first to ask a question for this course!" />
            )
          )}
          {activeTab === 'resources' && (
            <div className="grid md:grid-cols-2 gap-4">
              {filteredResources.length > 0 ? (
                filteredResources.map(r => <ResourceCard key={r.id} resource={r} />)
              ) : (
                <div className="md:col-span-2"><EmptyState title="No resources found" subtitle="Share a helpful study guide with your peers!" /></div>
              )}
            </div>
          )}
          {activeTab === 'my' && (
            myContributions.length > 0 ? (
              myContributions.map(item => (
                item.type === 'question' 
                ? <QuestionCard key={item.id} question={item as any} onClick={() => onSelectQuestion(item.id)} />
                : <ResourceCard key={item.id} resource={item as any} />
              ))
            ) : (
              <EmptyState title="No contributions yet" subtitle="Your questions and shared resources will appear here." />
            )
          )}
        </div>
      </div>
    </div>
  );
};

const EmptyState: React.FC<{ title: string; subtitle: string }> = ({ title, subtitle }) => (
  <div className="py-20 flex flex-col items-center justify-center text-center">
    <div className="w-20 h-20 bg-slate-100 rounded-full flex items-center justify-center mb-4">
      <svg className="w-10 h-10 text-slate-300" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M19 11H5m14 0a2 2 0 012 2v6a2 2 0 01-2 2H5a2 2 0 01-2-2v-6a2 2 0 012-2m14 0V9a2 2 0 00-2-2M5 11V9a2 2 0 012-2m0 0V5a2 2 0 012-2h6a2 2 0 012 2v2M7 7h10" /></svg>
    </div>
    <h3 className="text-lg font-bold text-slate-900">{title}</h3>
    <p className="text-slate-500">{subtitle}</p>
  </div>
);

export default Dashboard;

import React, { useState, useMemo } from 'react';
import { useApp } from '../context/AppContext';
import { getAISummary } from '../services/geminiService';

const QuestionDetailPage: React.FC<{ questionId: string; onBack: () => void }> = ({ questionId, onBack }) => {
  const { questions, answers, addAnswer, vote, user } = useApp();
  const [answerContent, setAnswerContent] = useState('');
  const [isAnonymous, setIsAnonymous] = useState(false);
  const [aiSummary, setAiSummary] = useState<string | null>(null);
  const [isAiLoading, setIsAiLoading] = useState(false);

  const question = questions.find(q => q.id === questionId);
  const questionAnswers = useMemo(() => answers.filter(a => a.questionId === questionId), [answers, questionId]);

  if (!question) return <div>Question not found</div>;

  const handleAISummary = async () => {
    setIsAiLoading(true);
    const summary = await getAISummary(question.content);
    setAiSummary(summary || null);
    setIsAiLoading(false);
  };

  const handlePostAnswer = (e: React.FormEvent) => {
    e.preventDefault();
    if (!answerContent.trim()) return;
    addAnswer({
      questionId,
      content: answerContent,
      anonymous: isAnonymous
    });
    setAnswerContent('');
  };

  return (
    <div className="max-w-4xl mx-auto space-y-8">
