import React, { createContext, useContext, useState, useEffect, useCallback } from 'react';
import { User, Question, Answer, Resource, KarmaReward } from '../types';
import { MOCK_USERS, MOCK_QUESTIONS, MOCK_RESOURCES } from '../constants';

interface AppContextType {
  user: User | null;
  questions: Question[];
  resources: Resource[];
  answers: Answer[];
  login: (email: string) => void;
  logout: () => void;
  addQuestion: (q: Partial<Question>) => void;
  addResource: (r: Partial<Resource>) => void;
  addAnswer: (a: Partial<Answer>) => void;
  vote: (targetId: string, type: 'question' | 'resource' | 'answer', value: 1 | -1) => void;
  updateKarma: (amount: number) => void;
}

const AppContext = createContext<AppContextType | undefined>(undefined);

export const AppProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [user, setUser] = useState<User | null>(null);
  const [questions, setQuestions] = useState<Question[]>(MOCK_QUESTIONS);
  const [resources, setResources] = useState<Resource[]>(MOCK_RESOURCES);
  const [answers, setAnswers] = useState<Answer[]>([]);
  // In a real app, track votes to prevent multiple votes by same user
  const [votedItems, setVotedItems] = useState<Set<string>>(new Set());

  // Simulation of persistent auth
  useEffect(() => {
    const savedUser = localStorage.getItem('studyhub_user');
    if (savedUser) {
      setUser(JSON.parse(savedUser));
    }
  }, []);

  const login = (email: string) => {
    if (!email.endsWith('.edu')) {
      alert("Only campus emails (.edu) are allowed.");
      return;
    }

    const isDemo = email === 'demo@university.edu';
    const newUser: User = {
      ...(isDemo ? MOCK_USERS[0] : {
        id: Math.random().toString(36).substr(2, 9),
        name: email.split('@')[0],
        karma: 0,
        contributions: 0,
        role: 'user',
        joinedAt: new Date().toISOString()
      }),
      email,
      avatar: isDemo ? MOCK_USERS[0].avatar : `https://picsum.photos/seed/${email}/200`,
    };

    setUser(newUser);
    localStorage.setItem('studyhub_user', JSON.stringify(newUser));
  };

  const logout = () => {
    setUser(null);
    localStorage.removeItem('studyhub_user');
  };

  const updateKarma = useCallback((amount: number) => {
    setUser(prev => {
      if (!prev) return null;
      const updated = { ...prev, karma: prev.karma + amount };
      localStorage.setItem('studyhub_user', JSON.stringify(updated));
      return updated;
    });
  }, []);

  const addQuestion = (q: Partial<Question>) => {
    if (!user) return;
    const newQ: Question = {
      id: Math.random().toString(36).substr(2, 9),
      title: q.title || '',
      content: q.content || '',
      course: q.course || '',
      tags: q.tags || [],
      userId: user.id,
      userName: q.anonymous ? 'Anonymous' : user.name,
      userAvatar: q.anonymous ? 'https://picsum.photos/seed/anon/200' : user.avatar,
      anonymous: !!q.anonymous,
      votes: 0,
      answerCount: 0,
      resolved: false,
      urgent: !!q.urgent,
      createdAt: new Date().toISOString(),
    };
    setQuestions(prev => [newQ, ...prev]);
    updateKarma(KarmaReward.ASK_QUESTION);
  };

  const addResource = (r: Partial<Resource>) => {
    if (!user) return;
    const newR: Resource = {
      id: Math.random().toString(36).substr(2, 9),
      title: r.title || '',
      description: r.description || '',
      course: r.course || '',
      tags: r.tags || [],
      link: r.link || '',
      userId: user.id,
      userName: user.name,
      votes: 0,
      downloads: 0,
      createdAt: new Date().toISOString(),
    };
    setResources(prev => [newR, ...prev]);
    updateKarma(KarmaReward.SHARE_RESOURCE);
  };

  const addAnswer = (a: Partial<Answer>) => {
    if (!user) return;
    const newA: Answer = {
      id: Math.random().toString(36).substr(2, 9),
      questionId: a.questionId || '',
      content: a.content || '',
      userId: user.id,
      userName: a.anonymous ? 'Anonymous' : user.name,
      userAvatar: a.anonymous ? 'https://picsum.photos/seed/anon/200' : user.avatar,
      anonymous: !!a.anonymous,
      votes: 0,
      isBest: false,
      createdAt: new Date().toISOString(),
    };
    setAnswers(prev => [newA, ...prev]);
    setQuestions(prev => prev.map(q => q.id === a.questionId ? { ...q, answerCount: q.answerCount + 1 } : q));
    updateKarma(KarmaReward.ANSWER_QUESTION);
  };

  const vote = (targetId: string, type: 'question' | 'resource' | 'answer', value: 1 | -1) => {
    // Basic anti-spam for the demo session
    if (votedItems.has(targetId)) return;

    setVotedItems(prev => new Set(prev).add(targetId));

    if (type === 'question') {
      setQuestions(prev => prev.map(q => q.id === targetId ? { ...q, votes: q.votes + value } : q));
    } else if (type === 'resource') {
      setResources(prev => prev.map(r => r.id === targetId ? { ...r, votes: r.votes + value } : r));
    } else if (type === 'answer') {
      setAnswers(prev => prev.map(ans => ans.id === targetId ? { ...ans, votes: ans.votes + value } : ans));
    }

    if (value === 1) {
      updateKarma(KarmaReward.RECEIVE_UPVOTE);
    }
  };

  return (
    <AppContext.Provider value={{ user, questions, resources, answers, login, logout, addQuestion, addResource, addAnswer, vote, updateKarma }}>
      {children}
    </AppContext.Provider>
  );
};

export const useApp = () => {
  const context = useContext(AppContext);
  if (!context) throw new Error("useApp must be used within an AppProvider");
  return context;
};

import React, { useState, useMemo } from 'react';
import { useApp } from '../context/AppContext';
import { QuestionCard, ResourceCard } from '../components/Cards';
import { POPULAR_COURSES } from '../constants';
import { BarChart, Bar, XAxis, Tooltip, ResponsiveContainer, Cell } from 'recharts';

const Dashboard: React.FC<{ onSelectQuestion: (id: string) => void; searchQuery: string }> = ({ onSelectQuestion, searchQuery }) => {
  const { questions, resources, user } = useApp();
  const [activeTab, setActiveTab] = useState<'questions' | 'resources' | 'my'>('questions');
  const [selectedCourse, setSelectedCourse] = useState<string | null>(null);

  const statsData = [
    { name: 'Questions', val: 124, color: '#3B82F6' },
    { name: 'Answers', val: 89, color: '#10B981' },
    { name: 'Materials', val: 45, color: '#8B5CF6' }
  ];

  const filteredQuestions = useMemo(() => {
    let qs = [...questions];
    if (searchQuery) {
      qs = qs.filter(q => 
        q.title.toLowerCase().includes(searchQuery.toLowerCase()) || 
        q.content.toLowerCase().includes(searchQuery.toLowerCase()) ||
        q.tags.some(t => t.toLowerCase().includes(searchQuery.toLowerCase()))
      );
    }
    if (selectedCourse) {
      qs = qs.filter(q => q.course === selectedCourse);
    }
    return qs;
  }, [questions, searchQuery, selectedCourse]);

  const filteredResources = useMemo(() => {
    let rs = [...resources];
    if (searchQuery) {
      rs = rs.filter(r => 
        r.title.toLowerCase().includes(searchQuery.toLowerCase()) || 
        r.description.toLowerCase().includes(searchQuery.toLowerCase()) ||
        r.tags.some(t => t.toLowerCase().includes(searchQuery.toLowerCase()))
      );
    }
    if (selectedCourse) {
      rs = rs.filter(r => r.course === selectedCourse);
    }
    return rs;
  }, [resources, searchQuery, selectedCourse]);

  const myContributions = useMemo(() => {
    const combined = [
      ...questions.filter(q => q.userId === user?.id).map(q => ({ ...q, itemType: 'question' as const })),
      ...resources.filter(r => r.userId === user?.id).map(r => ({ ...r, itemType: 'resource' as const }))
    ];
    return combined.sort((a, b) => new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime());
  }, [questions, resources, user]);

  return (
    <div className="grid lg:grid-cols-4 gap-8">
      {/* Sidebar - Visible on LG screens as true sidebar, on mobile at bottom */}
      <aside className="space-y-8 order-2 lg:order-1">
        <div className="bg-white rounded-2xl border border-slate-200 p-6 shadow-sm">
          <h3 className="text-sm font-bold text-slate-900 uppercase tracking-wider mb-4">Course Filter</h3>
          <div className="flex flex-col gap-1">
            <button 
              onClick={() => setSelectedCourse(null)}
              className={`text-left text-sm py-2 px-3 rounded-lg transition-colors ${!selectedCourse ? 'bg-blue-600 text-white font-medium' : 'hover:bg-slate-50 text-slate-600'}`}
            >
              All Courses
            </button>
            {POPULAR_COURSES.map(course => (
              <button 
                key={course}
                onClick={() => setSelectedCourse(course)}
                className={`text-left text-sm py-2 px-3 rounded-lg transition-colors ${selectedCourse === course ? 'bg-blue-600 text-white font-medium' : 'hover:bg-slate-50 text-slate-600'}`}
              >
                {course}
              </button>
            ))}
          </div>
        </div>

        <div className="bg-white rounded-2xl border border-slate-200 p-6 shadow-sm hidden lg:block">
          <h3 className="text-sm font-bold text-slate-900 uppercase tracking-wider mb-4">Today's Activity</h3>
          <div className="h-40 w-full">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={statsData}>
                <XAxis dataKey="name" fontSize={10} axisLine={false} tickLine={false} />
                <Tooltip 
                  cursor={{fill: 'transparent'}} 
                  contentStyle={{borderRadius: '12px', border: 'none', boxShadow: '0 10px 15px -3px rgb(0 0 0 / 0.1)'}} 
                />
                <Bar dataKey="val" radius={[4, 4, 4, 4]}>
                  {statsData.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill={entry.color} />
                  ))}
                </Bar>
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>
      </aside>

      {/* Main Area */}
      <div className="lg:col-span-3 space-y-6 order-1 lg:order-2">
        {searchQuery && (
          <div className="bg-blue-50 border border-blue-100 p-4 rounded-xl flex items-center justify-between">
            <p className="text-sm text-blue-800">Showing results for "<span className="font-bold">{searchQuery}</span>"</p>
            {selectedCourse && <span className="text-xs bg-blue-100 text-blue-700 px-2 py-1 rounded font-bold">{selectedCourse}</span>}
          </div>
        )}

        <div className="flex items-center gap-4 border-b border-slate-200 overflow-x-auto no-scrollbar">
          <button 
            onClick={() => setActiveTab('questions')}
            className={`pb-3 text-sm font-bold px-4 transition-all relative whitespace-nowrap ${activeTab === 'questions' ? 'text-blue-600' : 'text-slate-500 hover:text-slate-800'}`}
          >
            Questions ({filteredQuestions.length})
            {activeTab === 'questions' && <div className="absolute bottom-0 left-0 right-0 h-1 bg-blue-600 rounded-t-full"></div>}
          </button>
          <button 
            onClick={() => setActiveTab('resources')}
            className={`pb-3 text-sm font-bold px-4 transition-all relative whitespace-nowrap ${activeTab === 'resources' ? 'text-blue-600' : 'text-slate-500 hover:text-slate-800'}`}
          >
            Resources ({filteredResources.length})
            {activeTab === 'resources' && <div className="absolute bottom-0 left-0 right-0 h-1 bg-blue-600 rounded-t-full"></div>}
          </button>
          <button 
            onClick={() => setActiveTab('my')}
            className={`pb-3 text-sm font-bold px-4 transition-all relative whitespace-nowrap ${activeTab === 'my' ? 'text-blue-600' : 'text-slate-500 hover:text-slate-800'}`}
          >
            My Contributions
            {activeTab === 'my' && <div className="absolute bottom-0 left-0 right-0 h-1 bg-blue-600 rounded-t-full"></div>}
          </button>
        </div>

        <div className="grid gap-4">
          {activeTab === 'questions' && (
            filteredQuestions.length > 0 ? (
              filteredQuestions.map(q => <QuestionCard key={q.id} question={q} onClick={() => onSelectQuestion(q.id)} />)
            ) : (
              <EmptyState title="No questions found" subtitle="Try changing your filters or be the first to ask!" />
            )
          )}
          {activeTab === 'resources' && (
            <div className="grid md:grid-cols-2 gap-4">
              {filteredResources.length > 0 ? (
                filteredResources.map(r => <ResourceCard key={r.id} resource={r} />)
              ) : (
                <div className="md:col-span-2"><EmptyState title="No resources found" subtitle="Study guides shared by peers will appear here." /></div>
              )}
            </div>
          )}
          {activeTab === 'my' && (
            myContributions.length > 0 ? (
              myContributions.map(item => (
                item.itemType === 'question' 
                ? <QuestionCard key={item.id} question={item as any} onClick={() => onSelectQuestion(item.id)} />
                : <ResourceCard key={item.id} resource={item as any} />
              ))
            ) : (
              <EmptyState title="No contributions yet" subtitle="Start helping others to earn karma!" />
            )
          )}
        </div>
      </div>
    </div>
  );
};

const EmptyState: React.FC<{ title: string; subtitle: string }> = ({ title, subtitle }) => (
  <div className="py-20 flex flex-col items-center justify-center text-center px-4 bg-white rounded-2xl border border-slate-100 shadow-sm">
    <div className="w-16 h-16 bg-slate-50 rounded-full flex items-center justify-center mb-4">
      <svg className="w-8 h-8 text-slate-300" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M19 11H5m14 0a2 2 0 012 2v6a2 2 0 01-2 2H5a2 2 0 01-2-2v-6a2 2 0 012-2m14 0V9a2 2 0 00-2-2M5 11V9a2 2 0 012-2m0 0V5a2 2 0 012-2h6a2 2 0 012 2v2M7 7h10" /></svg>
    </div>
    <h3 className="text-lg font-bold text-slate-900">{title}</h3>
    <p className="text-slate-500 text-sm max-w-xs">{subtitle}</p>
  </div>
);

export default Dashboard;

import React, { useState } from 'react';
import { AppProvider, useApp } from './context/AppContext';
import Layout from './components/Layout';
import LandingPage from './pages/LandingPage';
import Dashboard from './pages/Dashboard';
import QuestionDetailPage from './pages/QuestionDetailPage';
import LeaderboardPage from './pages/LeaderboardPage';
import ProfilePage from './pages/ProfilePage';
import AskModal from './components/AskModal';
import ShareModal from './components/ShareModal';

const AppContent: React.FC = () => {
  const { user } = useApp();
  const [activeTab, setActiveTab] = useState('dashboard');
  const [selectedQuestionId, setSelectedQuestionId] = useState<string | null>(null);
  const [showAskModal, setShowAskModal] = useState(false);
  const [showShareModal, setShowShareModal] = useState(false);
  const [searchQuery, setSearchQuery] = useState('');

  if (!user) {
    return <LandingPage />;
  }

  // Routing Simulation
  const handleTabChange = (tab: string) => {
    setActiveTab(tab);
    setSelectedQuestionId(null);
    setSearchQuery('');
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const handleSearch = (term: string) => {
    setSearchQuery(term);
    setActiveTab('dashboard');
    setSelectedQuestionId(null);
  };

  const renderContent = () => {
    if (selectedQuestionId) {
      return <QuestionDetailPage questionId={selectedQuestionId} onBack={() => setSelectedQuestionId(null)} />;
    }

    switch (activeTab) {
      case 'dashboard':
        return <Dashboard onSelectQuestion={setSelectedQuestionId} searchQuery={searchQuery} />;
      case 'leaderboard':
        return <LeaderboardPage />;
      case 'profile':
        return <ProfilePage />;
      default:
        return <Dashboard onSelectQuestion={setSelectedQuestionId} searchQuery={searchQuery} />;
    }
  };

  return (
    <Layout activeTab={activeTab} onTabChange={handleTabChange} onSearch={handleSearch}>
      {renderContent()}

      {/* Floating Action Buttons */}
      <div className="fixed bottom-6 right-6 flex flex-col gap-4 z-40 items-end">
        {/* Share Resource FAB */}
        <div className="flex items-center gap-3 group">
          <span className="bg-indigo-900 text-white text-xs font-bold px-3 py-1.5 rounded-lg shadow-xl opacity-0 group-hover:opacity-100 transition-opacity whitespace-nowrap hidden sm:block">
            Share Resource
          </span>
          <button 
            onClick={() => setShowShareModal(true)}
            className="bg-indigo-600 hover:bg-indigo-700 text-white w-14 h-14 rounded-2xl shadow-2xl flex items-center justify-center transition-all hover:scale-110 active:scale-95"
            aria-label="Share Resource"
          >
            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 13h6m-3-3v6m5 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" />
            </svg>
          </button>
        </div>

        {/* Ask Question FAB */}
        <div className="flex items-center gap-3 group">
          <span className="bg-blue-900 text-white text-xs font-bold px-3 py-1.5 rounded-lg shadow-xl opacity-0 group-hover:opacity-100 transition-opacity whitespace-nowrap hidden sm:block">
            Ask Question
          </span>
          <button 
            onClick={() => setShowAskModal(true)}
            className="bg-blue-600 hover:bg-blue-700 text-white w-14 h-14 rounded-2xl shadow-2xl flex items-center justify-center transition-all hover:scale-110 active:scale-95"
            aria-label="Ask Question"
          >
            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 6v6m0 0v6m0-6h6m-6 0H6" />
            </svg>
          </button>
        </div>
      </div>

      <AskModal isOpen={showAskModal} onClose={() => setShowAskModal(false)} />
      <ShareModal isOpen={showShareModal} onClose={() => setShowShareModal(false)} />
    </Layout>
  );
};

const App: React.FC = () => {
  return (
    <AppProvider>
      <AppContent />
    </AppProvider>
  );
};

export default App;

